INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00413', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「舒米‧如妮戴著報童帽向我展現爽朗的笑容，黝黑的臉龐露出一口潔白的牙齒。她不但是《海稻米 願望》的主角，同時也是《太陽的孩子》的女主角原型。面向海洋的這一大片土地，曾經有金黃色的 稻穗隨風擺動，卻因為缺乏灌溉水源而逐漸荒廢。之後許多外來的商業開發案接踵而至，一方面對觀 光發展有所期待，另一方面也擔心生活和環境遭到破壞，當地居民因此陷入兩難。究竟要如何守護祖 先留下來的珍貴土地？這時舒米‧如妮便站出來號召村民共同復育故鄉的稻作。」 根據上文，作者所形塑的人物形象是：', '["有著純樸笑容與穿著，熱情好客的農村婦女", "對大海無比的嚮往，卻無法突破限制的女性", "明白地方困境，欲透過傳統產業文化發展特色的女性", "對發展地方觀光具商業頭腦，積極開發產業文創的女性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00414', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「我在九一一事件的三天前來到紐約，在那裡短暫求學的幾個月，我目睹了這個城市的重創，卻也見 識了它的堅強，在事發後很短的時間內，人們便恢復了正常生活。地鐵站裡的街頭藝人依舊辛勤地演 出著，斯文的民謠歌手、賺取學費的學生弦樂家、設備齊全的搖滾樂團、老邁的二胡演奏家……當然 也少不了用破銅爛鐵和水桶做鼓組的打擊樂手。偶爾，也會遇到車廂內演出的表演者，有的唱歌有的 演布偶劇，他們多半會在到站前向乘客們請求打賞，隨後轉往下一個車廂。」 根據上文，可以見到街頭表演在這個城市的文化風景中，扮演何種角色？', '["作為控訴社會階級、種族不平等的工具", "作為顯現市民音樂水準與各種才藝展現的舞臺", "作為底層民眾突破生活困境，謀求生活溫飽的方式", "作為展現多元文化靈動性、豐富性與生命力的象徵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00415', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「我覺得藝術、詩歌和宗教的存在，其目的，是輔助我們恢復新鮮的視覺，恢復富於感情的吸引力， 和一種更健全的人生意識。我們正需要它們，因為當我們上了年紀的時候，我們的感覺將逐漸麻木， 對於痛苦、冤屈和殘酷的情感將變為冷淡，我們的人生想像，也因過於注意冷酷和瑣碎的現實生活而 變成歪曲了。現在幸虧還有幾個大詩人和藝術家，他們的那種敏銳的感覺，那種美妙的情感反應，和 那種新奇的想像還沒有失掉，還可以行使他們的天職來維持我們道德上的良知，好比拿一面鏡子來照 我們已經遲鈍了的想像，使枯竭的神經興奮起來。藝術教我們在矯飾的世界裡保持著樸實真摯，使我 們回復到健康幸福的生活，使我們從過分智能活動所產生的昏熱中恢復過來。它可以使我們的感覺重 變敏銳，重使我們的理性和本有的天性發生聯繫，恢復原有的本性，把那脫離生活中已毀壞的部分收 集起來，重變成一個整體。」 根據上文，下列敘述何者最為正確？', '["人類過分智能活動導致失去道德良知", "藝術作品必然具有鮮豔美麗溫暖特徵", "文藝工作者的五官感知能力優於常人", "藝術可使人更為感覺敏銳及情感豐沛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00416', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '承上題，文中所謂「藝術教我們在矯飾的世界裡保持著樸實真摯，使我們回復到健康幸福的生活，使 我們從過分智能活動所產生的昏熱中恢復過來」，其文意主旨與下列選項何者最為符合？', '["鼓舞疲憊的心靈，抒解、開放僵硬閉鎖的心，就是藝術、文化", "美，到處都有。對於我們的眼睛，不是缺少美，而是缺少發現", "科學與藝術屬於整個世界，在它們面前，民族的障礙都消失了", "藝術不是真理。藝術是謊言，而這種謊言能教我們去認識真理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00417', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「鑿石為碑，疊石成塔，前者是人要在地上留存記憶，後者則是人要召喚天靈、與神對話。因此，石 頭其實已非石頭，而是一個舞台，一則文本，述說著人間的曾經與未了。當代哲學家薩里士（JohnSallis） 曾經說過，他喜歡尋訪墓園，讀碑遙想，倚牆而聽，所珍惜的不外就是彷彿劇場的世界和人生。」 下列選項，何者最貼近本文意旨？', '["在墓園立碑是為了供後人尋訪", "塔比碑更具有與神溝通的功能", "古人劇場演出常以石頭搭建舞台", "讀碑的意義在提示珍惜世界與人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00418', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「大體說來，農村生活是平靜的。農人的歲月往往仍是從播種到收穫之間日出而作、日入而息的單純 過程。他們把大部分的時間用在謀生上，並且以工作代替幻想，累了就睡。農人那種對土地的執著， 即使含有因代代相傳而來的強迫責任和保守情感，土地必定也一直令他們覺得有所擔當和歸屬，並因 而使他們有著某種說不出的永恆感吧。美本該無關乎現實，它讓你在觀賞中感到愉悅，在省思中有所 領悟和提昇，當美感只為賞玩時，其中並無多大的扣人心弦處。有一次，在淡水看到一位攝影家架起 組件精緻複雜的相機在河邊等待落日，而且雇請一位漁人駕著舢舨在預定的時間划過鏡頭中的水上。 我從渡船口的魚攤旁走過，猛想著：那位船夫事後看到那一剎那間攝下的那幅美麗畫面時，不知會有 怎樣的愉快感覺？現在，當我環顧四周的時候，我總覺得，除了這片寂靜大地的聲音之外，最深的美 質就是農人那種對生活永不放手的心靈了。然而，農人本身卻是最少歌頌田園景致的。那是由於親和 關係而形成的類似『相忘於江湖』的情懷嗎？或只因為長期的熟識已使他們對天地之美無動於衷了 呢？這些似乎也都不必去辨明了。」 根據上文，對於農人與田園關係之描述，最適合的是：', '["農人與田園水乳交融，是其堅實的生命依托", "農人僅視田園為工作場域，故無法體察其美", "田園對於農人而言，純粹是謀取衣食的工具", "農人因責任與慣性而固守田園，實充滿無奈"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00419', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '承上題，文中所舉攝影家之例，旨在說明何者？', '["除自然之美外，人為設計亦是成就藝術的重要面向", "美無涉於現實利益，純粹賞美方足以成就最高藝術", "美是令人愉悅的，透過適當安排足以彰顯其藝術性", "純為娛樂玩賞而創造的美，往往缺乏真正動人力量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00420', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「雙重約束是指在表達的時候，包含兩個以上互相衝突的指令，使他人言行設限，引致內在衝突、並 陷入於兩難之中。人類學家格雷戈里．貝特森GregoryBateson曾舉過一個例子。母親問孩子說：『你 過來抱著媽媽好嗎？』孩子過來擁抱媽媽了，媽媽卻流露出冷漠，以及不自在的神色。當孩子不抱媽 媽了，媽媽卻說：『你是不是不喜歡媽媽呢？』孩子不知如何是好？媽媽卻教訓孩子，要好好地控制 自己的情緒。上述的例子，媽媽正對孩子發出雙重約束的指令。第一個訊息是：『如果你不擁抱我， 就是不愛我。』第二個訊息是：『如果你擁抱我，你令我不舒服。』於是孩子便感到做也是錯，不做也 是錯，更重要的是，這位母親將問題歸咎於孩子情緒失控，而不是自己的冷漠態度。母親的說話彷彿 在歡迎孩子，但身體語言卻在拒絕。小孩子不能理解其中原因，只感到不能不聽從指令，遭受到拒絕 時又無法表達，被責難時更感到困惑，久而久之則內化成『我做什麼都錯』的想法 。」 依據上文，下列選項不符合文意的是：', '["訊息，不僅是口頭言語，也有包含身體語言", "母親表面示愛，身體語言卻拒絕，是因為孩子情緒控制不佳", "孩子接收雙重約束訊息太久後，會引致內在衝突，而無法作為", "「不擁抱就是不愛我」、「擁抱後，我卻不舒服」，就是雙重約束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00421', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '承上題，下列敘述何者不是「雙重約束」的訊息？', '["父親大聲地說：「誰亂動我的書？」母親說：「女兒想要看的。」父親輕聲細語：「女兒啊，多看看書 是好事哦！」", "小立跟母親說要到外地工作，母親一臉憂慮地對小立說：「好啊，你是應該到外地學習獨立過生活 了！」「可是你什麼都不會！」", "小明問：「爸爸，我可以吃冰嗎？」爸爸冷冷地說：「好啊！」小明吃著冰棒，爸爸說：「要死了，感 冒還沒好，怎麼可以吃冰！」", "女友跟男友說：「你竟然忘了我的生日，沒有準備禮物！」男友回應立刻去買，女友：「算了，你又 不是自動自發，我不要這種禮物！」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00422', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「永續發展，是指在保護環境的條件下既滿足當代人的需求，又以不損害後代人的需求為前瞻的發展 模式。」下列選項，與上文意旨最相近的是：', '["庖有肥肉，廄有肥馬", "斧斤以時入山林，材木不可勝用也", "如有不嗜殺人者，則天下之民，皆引領而望之矣", "謹庠序之教，申之以孝悌之義，頒白者不負戴於道路矣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
